import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.BEgbRHOA.js";const p=JSON.parse('{"title":"Корзина и оформление заказа","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier/cart-checkout.md","filePath":"guide/xcourier/cart-checkout.md","lastUpdated":1775746985000}'),r={name:"guide/xcourier/cart-checkout.md"};function o(c,a,h,n,u,s){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="корзина-и-оформление-заказа" tabindex="-1">Корзина и оформление заказа <a class="header-anchor" href="#корзина-и-оформление-заказа" aria-label="Permalink to &quot;Корзина и оформление заказа&quot;">​</a></h1><h2 id="корзина" tabindex="-1">Корзина <a class="header-anchor" href="#корзина" aria-label="Permalink to &quot;Корзина&quot;">​</a></h2><p>Корзина — третья вкладка нижней навигации. Здесь отображаются все добавленные товары:</p><ul><li>Изображение, название, вес каждого товара</li><li>Цена за единицу и количество (с возможностью изменения)</li><li>Общая стоимость позиции</li><li>Индикатор изменения цены (если цена товара изменилась после добавления)</li><li>Кнопка удаления товара</li></ul><p>Внизу экрана показана итоговая сумма заказа и кнопка «Оформить заказ».</p><div class="warning custom-block"><p class="custom-block-title">Важно</p><p>Все товары в корзине должны быть из одного магазина. При добавлении товара из другого магазина предыдущая корзина очищается.</p></div><h2 id="оформление-заказа-checkout" tabindex="-1">Оформление заказа (Checkout) <a class="header-anchor" href="#оформление-заказа-checkout" aria-label="Permalink to &quot;Оформление заказа (Checkout)&quot;">​</a></h2><p>На экране оформления заказа пользователь указывает:</p><h3 id="адрес-доставки" tabindex="-1">Адрес доставки <a class="header-anchor" href="#адрес-доставки" aria-label="Permalink to &quot;Адрес доставки&quot;">​</a></h3><ul><li>Поле адреса с автоподсказками (интеграция с сервисом геокодирования)</li><li>Детали: подъезд, домофон, квартира, этаж</li><li>Выбор города</li></ul><h3 id="способ-доставки" tabindex="-1">Способ доставки <a class="header-anchor" href="#способ-доставки" aria-label="Permalink to &quot;Способ доставки&quot;">​</a></h3><ul><li><strong>Курьерская доставка</strong> — рассчитывается стоимость через сервис доставки</li><li><strong>Самовывоз</strong> — бесплатно, забрать из магазина</li></ul><h3 id="способ-оплаты" tabindex="-1">Способ оплаты <a class="header-anchor" href="#способ-оплаты" aria-label="Permalink to &quot;Способ оплаты&quot;">​</a></h3><ul><li>Наличные</li><li>СБП (если включено администратором)</li></ul><h3 id="дополнительно" tabindex="-1">Дополнительно <a class="header-anchor" href="#дополнительно" aria-label="Permalink to &quot;Дополнительно&quot;">​</a></h3><ul><li>Комментарий к заказу</li><li>Опция «Оставить у двери» (для курьерской доставки)</li></ul><h2 id="расчет-стоимости-доставки" tabindex="-1">Расчёт стоимости доставки <a class="header-anchor" href="#расчет-стоимости-доставки" aria-label="Permalink to &quot;Расчёт стоимости доставки&quot;">​</a></h2><p>Стоимость курьерской доставки рассчитывается динамически:</p><ol><li>Определяются координаты магазина и адреса доставки</li><li>Выбирается подходящий тариф</li><li>Рассчитывается стоимость маршрута</li><li>Возвращается цена доставки в тенге</li></ol><p>Для городов без динамического расчёта используются фиксированные тарифы.</p><h2 id="подтверждение-заказа" tabindex="-1">Подтверждение заказа <a class="header-anchor" href="#подтверждение-заказа" aria-label="Permalink to &quot;Подтверждение заказа&quot;">​</a></h2><p>После нажатия «Оформить» показывается диалог подтверждения. При подтверждении:</p><ol><li>Заказ создаётся на сервере</li><li>Проверяется доступность магазина (расписание, временное закрытие)</li><li>Корзина очищается</li><li>Пользователь перенаправляется на страницу деталей заказа</li></ol>',23)])])}const k=l(r,[["render",o]]);export{p as __pageData,k as default};
